var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 9월 25일 런던, <color=#ffd34c>■■ ■■■</color> 지하 사원","JPN":"1888年9月25日　ロンドン、<color=#ffd34c>■■ ■■■</color>地下の寺院","ENG":"September 25, 1888, London, <color=#ffd34c>■■ ■■■</color> Underground Temple","TWN":"1888年9月25日 倫敦，<color=#ffd34c>■■ ■■■</color> 地下神廟","SCN":"1888年9月25日 伦敦，<color=#ffd34c>■■ ■■■</color> 地下神庙","DEU":"September 25, 1888, London, <color=#ffd34c>■■ ■■■</color> Underground Temple","FRA":"September 25, 1888, London, <color=#ffd34c>■■ ■■■</color> Underground Temple"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"우리 모두 기도합시다.","JPN":"皆、祈りを捧げましょう。","ENG":"Let us all pray.","TWN":"讓我們一起祈禱吧。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"이 의식을 통하여, 무가치한 저들이 유의미한 존재로 탈바꿈할 수 있도록 기도합시다.","JPN":"この儀式によって、無価値な彼らが意味のある存在として生まれ変われるよう、祈りを捧げましょう。","ENG":"Pray that our unworthiness will be transformed into meaningfulness through this ritual.","TWN":"透過這個儀式，祈禱那些毫無價值之人能夠變成有意義的存在。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>마그눔 오푸스</color>를 위한 기도를…….","JPN":"<color=#ffd34c>マグヌム・オプス</color>のための祈りを……","ENG":"Pray for <color=#ffd34c>Magnum Opus</color>...","TWN":"祈禱<color=#ffd34c>偉大傑作</color>……"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"천국의 회합을 가리던 장막은 모두 거두어졌으니.","JPN":"天国の会合を隠していたベールはすべて片付いた。","ENG":"As the veil covering the assembly of heaven has been drawn.","TWN":"遮蔽天國聚會的帷幕已被全部揭開。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"영혼을 신과 하나되게 하고, 소세계를 대세계와 하나되게 하고.","JPN":"魂と神を一つにし、小世界と大世界を一つにし。","ENG":"Let the soul become one with god, the small and big world unite.","TWN":"讓靈魂與神合一，讓小世界與大世界合一。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"여성성과 남성성을 하나되게 하고, 자아와 무자아를 하나되게 하소서.","JPN":"女性性と男性性を一つにし、自我と無我を一つにしたまえ。","ENG":"Let the two halves of men and women join together, and the self and selfless bond.","TWN":"讓女性與男性合一，讓自我與無我合一。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORAN_SWANSONG_NPC_NULL","text":{"KOREA":"지시하신 대로 경찰청과 신문사에 성명문을 전달하였습니다.","JPN":"指示どおり、警察庁と新聞社に声明文を伝えました。","ENG":"As you instructed, I have delivered the statement to the police and media.","TWN":"按照你的指示，已將聲明傳達給警察局和報社了。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"……고생했네.","JPN":"……ご苦労だった。","ENG":"...Good work.","TWN":"……辛苦了。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORAN_SWANSONG_NPC_NULL","text":{"KOREA":"한 가지, 궁금한 걸 여쭈어봐도 괜찮겠습니까?","JPN":"一つ、お聞きしてもよろしいでしょうか。","ENG":"May I ask one thing?","TWN":"有一件事，我可以問一下嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORAN_SWANSONG_NPC_NULL","text":{"KOREA":"복수귀의 실력을 의심하는 건 아니지만, 이런 식으로 단서를 남길 필요가 있을까요?","JPN":"復讐鬼の腕を疑っているわけではありませんが、こうして手がかりを残す必要がありますか。","ENG":"Though I do not doubt the Revenger, was it necessary to leave clues behind like this?","TWN":"我並不是懷疑復仇鬼的實力，但有必要這樣留下線索嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORAN_SWANSONG_NPC_NULL","text":{"KOREA":"추적당할 텐데요.","JPN":"追跡されやすくなりますが。","ENG":"Someone will start following them.","TWN":"總會被有心人追蹤到的。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"괜찮아. 심볼이라는 건 의식에서 아주 중요한 의미를 가지거든.","JPN":"大丈夫だ。シンボルというのは儀式で非常に重要な意味を持つ。","ENG":"No matter. Symbols have significant importance in rituals.","TWN":"沒關係。象徵在儀式中有著非常重要的意義。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"그저 별것도 아닌, 살인이 거창한 의미를 가지게 되고.","JPN":"大したことでもない殺人が仰々しい意味を持つようになり、","ENG":"The killing may seem like nothing, but it will take on a greater meaning.","TWN":"殺戮原本只不過是件微不足道的事情，但卻會因此變得意義重大。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"우매한 대중들은 그로 하여금 경외심마저 품게 되겠지.","JPN":"愚かな大衆は畏敬の念すら抱くだろう。","ENG":"The ignorant public will be in awe.","TWN":"愚昧的群眾甚至會對此心生敬畏。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"부정적 감정과 집단 무의식의 발현은 결국 불가능한 일을 현실로 만들어 줄 거라네.","JPN":"ネガティブな感情と、集合的無意識の発現は不可能なことを現実にさせてくれる。","ENG":"The negative emotions and the manifestation of the collective unconscious will turn the impossible into reality.","TWN":"負面情感和集體無意識的顯現，最終會將不可能的事情變為現實。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"내 최후의 걸작, <color=#ffd34c>심야의 살인마</color>라는 심볼에 의해서 말이야.","JPN":"私の最後の傑作、<color=#ffd34c>深夜の殺人鬼</color>というシンボルによってな。","ENG":"With my final masterpiece, a symbol called the <color=#ffd34c>Midnight Killer</color>, that is.","TWN":"我的最後傑作，由<color=#ffd34c>午夜殺人魔</color>這個象徵所引導。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간\\n로열 오페라 하우스","JPN":"同時刻\\nロイヤルオペラハウス","ENG":"[[","TWN":"同一時間\\n皇家歌劇院","SCN":"同一时间\\n皇家歌剧院","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"커튼콜은 여기까지.","JPN":"カーテンコールはここまで。","ENG":"This is where the curtain call ends.","TWN":"謝幕演出到此結束。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"신사 숙녀 여러분, 저희 무대를 보러 와 주셔서 감사합니다.","JPN":"レディースアンドジェントルマン、私たちの舞台を見に来ていただきありがとうございました。","ENG":"Ladies and gentlemen, thank you all for coming tonight to see our performance.","TWN":"女士們先生們，感謝大家前來觀看。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};